import { useState, useEffect, useRef } from "react";
import { sendChatMessage } from "../services/api";
import "./ChatBox.css";

function ChatBox() {
  const userId = localStorage.getItem("user_id");
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([
    { sender: "Doctor-AI", text: "Hello 🙂 I’m glad you reached out. What’s your name?" }
  ]);
  const [reportPdf, setReportPdf] = useState(null);
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  const sendMessage = async () => {
    if (!message.trim()) return;

    const userMsg = message;
    setMessage("");
    setChat(prev => [...prev, { sender: "You", text: userMsg }]);

    const res = await sendChatMessage({ user_id: userId, message: userMsg });

    setChat(prev => [...prev, { sender: "Doctor-AI", text: res.data.reply }]);

    if (res.data.report_pdf) {
      setReportPdf(res.data.report_pdf);
    }
  };

  return (
    <div className="chatbox-container">
      <div className="chat-messages">
        {chat.map((c, i) => (
          <div key={i} className={c.sender === "You" ? "user" : "doctor"}>
            <b>{c.sender}:</b> {c.text}
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      {reportPdf && (
        <a
          href={`http://127.0.0.1:5000/${reportPdf}`}
          target="_blank"
          rel="noreferrer"
        >
          📄 Download Medical Report
        </a>
      )}

      <div className="chat-input">
        <input
          value={message}
          onChange={e => setMessage(e.target.value)}
          onKeyDown={e => e.key === "Enter" && sendMessage()}
          placeholder="Type your message..."
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
}

export default ChatBox;
